/**
 * Query-level tests for parallel partitioned prefix-run group aggregation. The parallel path is forced with a zero
 * min-estimate; results must match the sequential semantics exactly (same groups, same counts).
 */
public class LmdbParallelPrefixRunGroupsTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@AfterEach
	public void tearDown() {
		System.clearProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY);
		if (repository != null) {
			repository.shutDown();
		}
	}

	@Test
	public void countStarPerPredicateRunsParallel() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		openSmallRepository();

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		assertThat(countByBinding("SELECT ?p (COUNT(*) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p", "p"))
				.isEqualTo(Map.of(EX + "knows", 3L, EX + "likes", 2L, EX + "tag", 1L));
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void groupWithoutAggregatesRunsParallel() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		openSmallRepository();

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			assertThat(QueryResults
					.asList(conn.prepareTupleQuery("SELECT ?p WHERE { ?s ?p ?o } GROUP BY ?p").evaluate())
					.stream()
					.map(bs -> bs.getValue("p").stringValue())
					.sorted())
							.containsExactly(EX + "knows", EX + "likes", EX + "tag");
		}
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void defaultThresholdStaysSequentialOnSmallStores() {
		openSmallRepository();

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		assertThat(countByBinding("SELECT ?p (COUNT(*) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p", "p"))
				.isEqualTo(Map.of(EX + "knows", 3L, EX + "likes", 2L, EX + "tag", 1L));
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isEqualTo(before);
	}

	@Test
	public void outDegreeCountsMatchOnLargerRandomDataset() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		Map<String, Long> expected = openRandomRepository();

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		assertThat(countByBinding("SELECT ?s (COUNT(*) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?s", "s"))
				.isEqualTo(expected);
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void countDistinctObjectsPerPredicateMatchesOnLargerRandomDataset() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		Map<String, java.util.Set<String>> distinctObjects = new HashMap<>();
		Random random = new Random(11);
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI[] predicates = new IRI[5];
			for (int i = 0; i < predicates.length; i++) {
				predicates[i] = vf.createIRI(EX, "p" + i);
			}
			for (int i = 0; i < 4000; i++) {
				IRI subject = vf.createIRI(EX, "s" + random.nextInt(500));
				IRI predicate = predicates[random.nextInt(predicates.length)];
				IRI object = vf.createIRI(EX, "o" + random.nextInt(300));
				conn.add(subject, predicate, object);
				distinctObjects.computeIfAbsent(predicate.stringValue(), k -> new java.util.HashSet<>())
						.add(object.stringValue());
			}
		}
		Map<String, Long> expected = new HashMap<>();
		distinctObjects.forEach((p, objects) -> expected.put(p, (long) objects.size()));

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		assertThat(countByBinding("SELECT ?p (COUNT(DISTINCT ?o) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p", "p"))
				.isEqualTo(expected);
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isGreaterThan(before);
	}

	@Test
	public void skewedPredicateCountsSurviveRawBoundarySplits() {
		System.setProperty(LmdbNativeParallelPrefixRuns.PARALLEL_MIN_ESTIMATE_PROPERTY, "0");
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		Map<String, Long> expected = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI heavy = vf.createIRI(EX, "heavy");
			IRI light = vf.createIRI(EX, "light");
			IRI rare = vf.createIRI(EX, "rare");
			// one predicate dominates: raw-key partition boundaries land inside its run and the merge must
			// stitch the partial counts back together
			for (int i = 0; i < 3000; i++) {
				conn.add(vf.createIRI(EX, "hs" + i), heavy, vf.createIRI(EX, "ho" + (i % 37)));
			}
			for (int i = 0; i < 40; i++) {
				conn.add(vf.createIRI(EX, "ls" + i), light, vf.createIRI(EX, "lo" + i));
			}
			conn.add(vf.createIRI(EX, "rs"), rare, vf.createIRI(EX, "ro"));
			expected.put(heavy.stringValue(), 3000L);
			expected.put(light.stringValue(), 40L);
			expected.put(rare.stringValue(), 1L);
		}

		long before = LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get();
		assertThat(countByBinding("SELECT ?p (COUNT(*) AS ?c) WHERE { ?s ?p ?o } GROUP BY ?p", "p"))
				.isEqualTo(expected);
		assertThat(LmdbNativeParallelPrefixRuns.PARALLEL_RUNS.get()).isGreaterThan(before);
	}

	private void openSmallRepository() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI knows = vf.createIRI(EX, "knows");
			IRI likes = vf.createIRI(EX, "likes");
			IRI tag = vf.createIRI(EX, "tag");
			conn.add(vf.createIRI(EX, "s1"), knows, vf.createIRI(EX, "alice"));
			conn.add(vf.createIRI(EX, "s2"), knows, vf.createIRI(EX, "alice"));
			conn.add(vf.createIRI(EX, "s3"), knows, vf.createIRI(EX, "bob"));
			conn.add(vf.createIRI(EX, "s4"), likes, vf.createIRI(EX, "carol"));
			conn.add(vf.createIRI(EX, "s5"), likes, vf.createIRI(EX, "carol"));
			conn.add(vf.createIRI(EX, "s6"), tag, vf.createIRI(EX, "dave"));
		}
	}

	/** Loads a deterministic pseudo-random graph and returns the expected per-subject statement counts. */
	private Map<String, Long> openRandomRepository() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		Map<String, Long> expected = new HashMap<>();
		Random random = new Random(7);
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI[] predicates = new IRI[6];
			for (int i = 0; i < predicates.length; i++) {
				predicates[i] = vf.createIRI(EX, "p" + i);
			}
			java.util.Set<String> seen = new java.util.HashSet<>();
			for (int i = 0; i < 4000; i++) {
				IRI subject = vf.createIRI(EX, "s" + random.nextInt(700));
				IRI predicate = predicates[random.nextInt(predicates.length)];
				IRI object = vf.createIRI(EX, "o" + random.nextInt(900));
				if (seen.add(subject.stringValue() + "|" + predicate.stringValue() + "|" + object.stringValue())) {
					conn.add(subject, predicate, object);
					expected.merge(subject.stringValue(), 1L, Long::sum);
				}
			}
		}
		return expected;
	}

	private Map<String, Long> countByBinding(String query, String keyBinding) {
		Map<String, Long> counts = new HashMap<>();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			for (BindingSet bs : QueryResults.asList(conn.prepareTupleQuery(query).evaluate())) {
				counts.put(bs.getValue(keyBinding).stringValue(), ((Literal) bs.getValue("c")).longValue());
			}
		}
		return counts;
	}
}
